-- ============================================================
-- Reset Klasifikasi Arsip Pemda - Permendagri Nomor 83 Tahun 2022
-- Sumber: bagian B, KODE KLASIFIKASI ARSIP DI LINGKUNGAN PEMERINTAH DAERAH
-- Catatan: menghapus klasifikasi/JRA lama yang tidak sesuai karena surat keluar
-- belum memakai kode tersebut, lalu menanam ulang kode resmi Pemda.
-- ============================================================

DELETE FROM jra;
DELETE FROM klasifikasi;

ON CONFLICT (kode) DO UPDATE
  SET nama = EXCLUDED.nama,
      keterangan = EXCLUDED.keterangan;
